insert into public.anatomy_structures (slug, name_ro, name_latin, tissue, body_region, model_selection_id, description_ro, function_ro) values
  ('frontal', 'Os frontal', 'Os frontale', 'os', 'cap_craniu', 'frontal', 'Os plat ce formează fruntea și partea anterioară a bolții craniene.', 'Protejează lobii frontali ai creierului și formează plafonul orbitelor.'),
  ('parietal', 'Oase parietale', 'Os parietale', 'os', 'cap_craniu', 'parietal', 'Două oase pereche ce alcătuiesc părțile laterale și superioare ale calotei craniene.', 'Protejează emisferele cerebrale.'),
  ('temporal', 'Oase temporale', 'Os temporale', 'os', 'cap_craniu', 'temporal', 'Conțin urechea internă și medie; situate lateral, sub parietale.', 'Adăpostesc structurile auditive și de echilibru.'),
  ('occipital', 'Os occipital', 'Os occipitale', 'os', 'cap_craniu', 'occipital', 'Os posterior al craniului, cu marele orificiu (foramen magnum).', 'Permite trecerea măduvei spinării și protejează cerebelul.'),
  ('sfenoid', 'Os sfenoid', 'Os sphenoidale', 'os', 'cap_craniu', 'sfenoid', 'Os central în formă de fluture, articulat cu toate celelalte oase craniene.', 'Susține baza craniului și conține șaua turcească pentru hipofiză.'),
  ('etmoid', 'Os etmoid', 'Os ethmoidale', 'os', 'cap_craniu', 'etmoid', 'Os ușor și spongios, situat între orbite, formând tavanul cavității nazale.', 'Suport pentru mucoasa olfactivă; conține celulele etmoidale.'),
  ('maxilar', 'Maxilare', 'Maxilla', 'os', 'fata', 'maxilar', 'Formează mandibula superioară și conțin alveolele dentare superioare.', 'Susțin dentiția superioară și formează plafonul cavității bucale.'),
  ('mandibula', 'Mandibulă', 'Mandibula', 'os', 'fata', 'mandibula', 'Singurul os mobil al craniului; formează maxilarul inferior.', 'Permite masticația și articularea vorbirii.'),
  ('zigomatic', 'Oase zigomatice', 'Os zygomaticum', 'os', 'fata', 'zigomatic', 'Oasele pomeților obrajilor.', 'Conturează fața și protejează lateral orbitele.'),
  ('nazal', 'Oase nazale', 'Os nasale', 'os', 'fata', 'nazal', 'Două oase mici ce formează puntea nasului.', 'Susțin partea superioară a piramidei nazale.'),
  ('lacrimal', 'Oase lacrimale', 'Os lacrimale', 'os', 'fata', 'lacrimal', 'Cele mai mici oase ale feței, situate în peretele medial al orbitei.', 'Conțin canalul nazo-lacrimal.'),
  ('palatin', 'Oase palatine', 'Os palatinum', 'os', 'fata', 'palatin', 'Formează partea posterioară a palatului dur.', 'Separă cavitatea bucală de cea nazală.'),
  ('vomer', 'Vomer', 'Vomer', 'os', 'fata', 'vomer', 'Os subțire ce formează partea inferioară a septului nazal.', 'Divide cavitatea nazală în două fose.'),
  ('cornet-inf', 'Cornete nazale inferioare', 'Concha nasalis inferior', 'os', 'fata', 'cornet-inf', 'Lame osoase încârligate în peretele lateral al cavității nazale.', 'Încălzesc și umidifică aerul inspirat.'),
  ('ciocan', 'Ciocane (Maleole)', 'Malleus', 'os', 'ureche_medie', 'ciocan', 'Cel mai mare osișor al urechii medii, atașat de timpan.', 'Transmite vibrațiile timpanului către nicovală.'),
  ('nicovala', 'Nicovale', 'Incus', 'os', 'ureche_medie', 'nicovala', 'Os în formă de nicovală, situat între ciocan și scăriță.', 'Continuă transmiterea vibrațiilor sonore.'),
  ('scarita', 'Scărițe', 'Stapes', 'os', 'ureche_medie', 'scarita', 'Cel mai mic os din corp; sprijinit pe fereastra ovală.', 'Transmite vibrațiile către urechea internă.'),
  ('hioid', 'Os hioid', 'Os hyoideum', 'os', 'gat', 'hioid', 'Os în formă de potcoavă, suspendat în gât, fără articulații cu alte oase.', 'Punct de inserție pentru mușchii limbii și ai laringelui.'),
  ('vert-cervicale', 'Vertebre cervicale (C1–C7)', 'Vertebrae cervicales', 'os', 'coloana', 'vert-cervicale', 'Cele 7 vertebre ale gâtului, cu Atlas (C1) și Axis (C2) ca primele două.', 'Susțin capul și permit rotația și flexia gâtului.'),
  ('vert-toracice', 'Vertebre toracice (T1–T12)', 'Vertebrae thoracicae', 'os', 'coloana', 'vert-toracice', 'Vertebrele zonei toracice, articulate cu coastele.', 'Punct de inserție pentru coaste; protejează măduva.'),
  ('vert-lombare', 'Vertebre lombare (L1–L5)', 'Vertebrae lumbales', 'os', 'coloana', 'vert-lombare', 'Cele mai mari vertebre, situate în zona inferioară a spatelui.', 'Susțin greutatea trunchiului superior.'),
  ('sacrum', 'Sacrum', 'Os sacrum', 'os', 'coloana', 'sacrum', 'Os triunghiular format prin fuziunea a 5 vertebre sacrale.', 'Conectează coloana cu pelvisul.'),
  ('coccis', 'Coccis', 'Os coccygis', 'os', 'coloana', 'coccis', 'Vârful coloanei, format din 3–5 vertebre fuzionate.', 'Punct de atașare pentru mușchii planșeului pelvian.'),
  ('stern', 'Stern', 'Sternum', 'os', 'torace', 'stern', 'Os plat central al toracelui, format din manubriu, corp și apendicele xifoid.', 'Protejează inima și plămânii; punct de inserție pentru coaste.'),
  ('coaste', 'Coaste', 'Costae', 'os', 'torace', 'coaste', '12 perechi: 7 adevărate, 3 false, 2 flotante.', 'Formează cutia toracică și protejează organele vitale.'),
  ('clavicula', 'Clavicule', 'Clavicula', 'os', 'umar_centura_scapulara', 'clavicula', 'Os lung în formă de S, situat orizontal deasupra primei coaste.', 'Conectează membrul superior de torace.'),
  ('scapula', 'Scapule (omoplați)', 'Scapula', 'os', 'umar_centura_scapulara', 'scapula', 'Oase plate triunghiulare situate posterior pe torace.', 'Articulație pentru humerus; mobilitate amplă a brațului.'),
  ('humerus', 'Humerus', 'Humerus', 'os', 'brat', 'humerus', 'Cel mai mare os al membrului superior, între umăr și cot.', 'Suport pentru mușchii brațului; permite mișcările umărului.'),
  ('radius', 'Radius', 'Radius', 'os', 'antebrat', 'radius', 'Osul lateral al antebrațului, pe partea policelui.', 'Permite rotația antebrațului (pronație/supinație).'),
  ('ulna', 'Ulnă (cubitus)', 'Ulna', 'os', 'antebrat', 'ulna', 'Osul medial al antebrațului, formează vârful cotului.', 'Stabilizează articulația cotului.'),
  ('carp', 'Oase carpiene', 'Ossa carpi', 'os', 'mana', 'carp', '8 oase pe fiecare mână, dispuse pe două rânduri (scafoid, semilunar, piramidal etc.).', 'Formează încheietura mâinii; permit mobilitate fină.'),
  ('metacarp', 'Metacarpiene', 'Ossa metacarpi', 'os', 'mana', 'metacarp', '5 oase lungi în palma fiecărei mâini.', 'Susțin palma și articulează degetele.'),
  ('falange-mana', 'Falange (mână)', 'Phalanges manus', 'os', 'mana', 'falange-mana', '14 falange pe mână: 2 pentru police, 3 pentru fiecare deget.', 'Permit mișcarea fină a degetelor.'),
  ('coxal', 'Oase coxale', 'Os coxae', 'os', 'pelvis', 'coxal', 'Fiecare format din ilion, ischion și pubis fuzionate.', 'Formează pelvisul; suportă greutatea trunchiului.'),
  ('femur', 'Femur', 'Femur', 'os', 'coapsa_sold_genunchi', 'femur', 'Cel mai lung și puternic os din corp.', 'Suportă greutatea corpului în mers și sprijin.'),
  ('rotula', 'Rotule (patelă)', 'Patella', 'os', 'coapsa_sold_genunchi', 'rotula', 'Os sesamoid în fața articulației genunchiului.', 'Protejează genunchiul și optimizează acțiunea cvadricepsului.'),
  ('tibia', 'Tibia', 'Tibia', 'os', 'gamba', 'tibia', 'Osul medial și mai gros al gambei.', 'Suportă greutatea corpului între genunchi și gleznă.'),
  ('fibula', 'Fibulă (peroneu)', 'Fibula', 'os', 'gamba', 'fibula', 'Osul subțire lateral al gambei.', 'Stabilizează glezna; punct de inserție musculară.'),
  ('tars', 'Oase tarsiene', 'Ossa tarsi', 'os', 'picior', 'tars', '7 oase pe picior, inclusiv calcaneu (călcâi) și astragal.', 'Formează glezna și partea posterioară a piciorului.'),
  ('metatars', 'Metatarsiene', 'Ossa metatarsi', 'os', 'picior', 'metatars', '5 oase lungi în partea mijlocie a fiecărui picior.', 'Susțin bolta plantară și transferă greutatea.'),
  ('falange-picior', 'Falange (picior)', 'Phalanges pedis', 'os', 'picior', 'falange-picior', '14 falange pe picior: 2 pentru haluce, 3 pentru fiecare deget.', 'Permit propulsia în mers și echilibrul.')
insert into public.ai_knowledge_entries (tissue, structure_slug, model_selection_id, body_region, category, title_ro, content_ro, priority) values
  ('os', 'frontal', 'frontal', 'cap_craniu', 'anatomie', 'Context anatomic: Os frontal', 'Os plat ce formează fruntea și partea anterioară a bolții craniene. Funcție principală: Protejează lobii frontali ai creierului și formează plafonul orbitelor.', 7),
  ('os', 'frontal', 'frontal', 'cap_craniu', 'simptome', 'Simptome posibile pentru Os frontal', 'durere locală după traumatism cranian, sensibilitate la atingere, umflare sau plagă la nivelul scalpului; semnele de alarmă includ confuzie, pierdere de cunoștință, vărsături repetate, somnolență neobișnuită, convulsii, slăbiciune, amorțeală sau scurgere de lichid/sânge din nas ori urechi.', 6),
  ('os', 'frontal', 'frontal', 'cap_craniu', 'cauze_posibile', 'Cauze posibile pentru durerea la Os frontal', 'lovitură directă, cădere, accident sportiv sau rutier; durerea poate veni din contuzie, fractură craniană, leziuni ale scalpului sau complicații intracraniene asociate traumatismului.', 6),
  ('os', 'frontal', 'frontal', 'cap_craniu', 'recomandari', 'Măsuri educaționale pentru Os frontal', 'după traumatisme craniene cu simptome neurologice, pierdere de cunoștință, vărsături, agravare sau suspiciune de fractură este necesară evaluare urgentă; până la evaluare se evită efortul și se monitorizează starea neurologică.', 5),
  ('os', 'frontal', 'frontal', 'cap_craniu', 'semne_alarma', 'Semne de alarmă pentru Os frontal', 'apel urgent la medic/112 pentru pierdere de cunoștință, confuzie, convulsii, deficit neurologic, durere severă progresivă, plagă deschisă sau suspiciune de fractură deschisă.', 8),
  ('os', 'frontal', 'frontal', 'cap_craniu', 'intrebari_clarificare', 'Întrebări utile pentru Os frontal', 'A existat lovitură la cap sau cădere? A apărut pierdere de cunoștință, vărsătură, confuzie sau somnolență? Durerea se agravează? Există sângerare sau plagă?', 4),
  ('os', 'parietal', 'parietal', 'cap_craniu', 'anatomie', 'Context anatomic: Oase parietale', 'Două oase pereche ce alcătuiesc părțile laterale și superioare ale calotei craniene. Funcție principală: Protejează emisferele cerebrale.', 7),
