  ('os', 'coaste', 'coaste', 'torace', 'intrebari_clarificare', 'Întrebări utile pentru Coaste', 'Te doare când inspiri adânc? Ai dificultate de respirație, tuse cu sânge sau accident puternic? Durerea este locală la apăsare?', 4),
  ('os', 'clavicula', 'clavicula', 'umar_centura_scapulara', 'anatomie', 'Context anatomic: Clavicule', 'Os lung în formă de S, situat orizontal deasupra primei coaste. Funcție principală: Conectează membrul superior de torace.', 7),
  ('os', 'clavicula', 'clavicula', 'umar_centura_scapulara', 'simptome', 'Simptome posibile pentru Clavicule', 'durere deasupra toracelui/umărului, umflare, vânătaie, umăr căzut, proeminență sau durere la mișcarea brațului.', 6),
  ('os', 'clavicula', 'clavicula', 'umar_centura_scapulara', 'cauze_posibile', 'Cauze posibile pentru durerea la Clavicule', 'cădere pe umăr, sport, bicicletă, accident; clavicula se fracturează frecvent prin impact pe umăr sau mână întinsă.', 6),
  ('os', 'clavicula', 'clavicula', 'umar_centura_scapulara', 'recomandari', 'Măsuri educaționale pentru Clavicule', 'imobilizare provizorie cu eșarfă/sling și evaluare medicală pentru deformare, durere severă sau limitare majoră; recuperarea include controlul durerii și mobilizare ghidată după recomandare.', 5),
  ('os', 'clavicula', 'clavicula', 'umar_centura_scapulara', 'semne_alarma', 'Semne de alarmă pentru Clavicule', 'urgență pentru deformare, amorțeală/slăbiciune în braț, piele palidă/rece, plagă deschisă sau traumă de energie mare.', 8),
